Fill in the blanks to configure Spring Security so that all URLs starting with '/employee/' are protected and require the 'EMPLOYEE' role. @Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
                .authorizeRequests()
                .__("/employee/__").__("EMPLOYEE")
                .anyRequest().permitAll()
                .and()
                .formLogin()
                .and()
                .logout();
    }
}

